    30→/**
    31→ * Checkpoint barriers are used to align checkpoints throughout the streaming topology. The barriers
    32→ * are emitted by the sources when instructed to do so by the JobManager. When operators receive a
    33→ * CheckpointBarrier on one of its inputs, it knows that this is the point between the
    34→ * pre-checkpoint and post-checkpoint data.
    35→ *
    36→ * <p>Once an operator has received a checkpoint barrier from all its input channels, it knows that
    37→ * a certain checkpoint is complete. It can trigger the operator specific checkpoint behavior and
    38→ * broadcast the barrier to downstream operators.
    39→ *
    40→ * <p>Depending on the semantic guarantees, may hold off post-checkpoint data until the checkpoint
    41→ * is complete (exactly once).
    42→ *
    43→ * <p>The checkpoint barrier IDs are strictly monotonous increasing.
    44→ */
    45→public class CheckpointBarrier extends RuntimeEvent {
    46→
    47→    private final long id;
    48→    private final long timestamp;
    49→    private final CheckpointOptions checkpointOptions;
    50→
    51→    public CheckpointBarrier(long id, long timestamp, CheckpointOptions checkpointOptions) {
    52→        this.id = id;
    53→        this.timestamp = timestamp;
    54→        this.checkpointOptions = checkNotNull(checkpointOptions);
    55→    }
    56→
    57→    public long getId() {
    58→        return id;
    59→    }
    60→
    61→    public long getTimestamp() {
    62→        return timestamp;
    63→    }
    64→
    65→    public CheckpointOptions getCheckpointOptions() {
    66→        return checkpointOptions;
    67→    }
    68→
    69→    public CheckpointBarrier withOptions(CheckpointOptions checkpointOptions) {
    70→        return this.checkpointOptions == checkpointOptions
    71→                ? this
    72→                : new CheckpointBarrier(id, timestamp, checkpointOptions);
    73→    }
    74→
    75→    // ------------------------------------------------------------------------
    76→    // Serialization
    77→    // ------------------------------------------------------------------------
    78→
    79→    //
